**목표:** `lib/site-diff-engine.ts`와 `tests/unit/site-diff-engine.test.ts`를 TDD로 생성하고 커밋합니다.

**규칙:** 이 두 파일만 건드리세요. 다른 파일 절대 수정 금지.

---

**Step 1: `tests/unit/site-diff-engine.test.ts` 생성**

```ts
import test from "node:test";
import assert from "node:assert/strict";
import { diffSiteRuns } from "../../lib/site-diff-engine.ts";
import type { Site, SiteRunResult, SitePageCapture } from "../../lib/site-types.ts";

function page(url: string, hash: string, screenshotPath = `${url}.png`): SitePageCapture {
  return {
    url, finalUrl: url, httpStatus: 200,
    domHash: hash, domSerialized: "",
    screenshotPath, capturedAt: "2026-06-04T00:00:00.000Z",
  };
}

function run(id: string, pages: SitePageCapture[]): SiteRunResult {
  return {
    runId: id, siteId: "s",
    startedAt: "2026-06-04T00:00:00.000Z", finishedAt: "2026-06-04T00:01:00.000Z",
    status: "completed", pages, errors: [],
  };
}

const baseSite: Site = {
  id: "s", name: "s",
  crawl: { startUrls: [], maxDepth: 0, maxPages: 0, allowSubdomains: false },
  visual: { enabled: false, maskSelectors: [], threshold: 0.1, maxDiffRatio: 0.01, viewport: { width: 1280, height: 800 } },
  dom: { enabled: true, ignoreSelectors: [], normalizeWhitespace: true },
  createdAt: "", updatedAt: "",
};

const stubVisual = async () => ({ diffPixels: 0, diffRatio: 0, diffImagePath: "" });

test("identical when both runs share urls and hashes", async () => {
  const report = await diffSiteRuns(baseSite, run("a", [page("/x", "h1")]), run("b", [page("/x", "h1")]), stubVisual);
  assert.equal(report.overall, "identical");
  assert.equal(report.pageDiffs[0].status, "identical");
});

test("domChanged when hash differs and visual matches", async () => {
  const report = await diffSiteRuns(baseSite, run("a", [page("/x", "h1")]), run("b", [page("/x", "h2")]), stubVisual);
  assert.equal(report.pageDiffs[0].status, "domChanged");
  assert.equal(report.pageDiffs[0].severity, "warning");
});

test("visualChanged when hash matches and visual differs", async () => {
  const visual = async () => ({ diffPixels: 9999, diffRatio: 0.5, diffImagePath: "d.png" });
  const report = await diffSiteRuns(
    { ...baseSite, visual: { ...baseSite.visual, enabled: true } },
    run("a", [page("/x", "h1")]), run("b", [page("/x", "h1")]), visual
  );
  assert.equal(report.pageDiffs[0].status, "visualChanged");
});

test("both when hash and visual both differ", async () => {
  const visual = async () => ({ diffPixels: 9999, diffRatio: 0.5, diffImagePath: "d.png" });
  const report = await diffSiteRuns(
    { ...baseSite, visual: { ...baseSite.visual, enabled: true } },
    run("a", [page("/x", "h1")]), run("b", [page("/x", "h2")]), visual
  );
  assert.equal(report.pageDiffs[0].status, "both");
  assert.equal(report.pageDiffs[0].severity, "critical");
});

test("missing when baseline url not in current", async () => {
  const report = await diffSiteRuns(baseSite, run("a", [page("/x", "h1")]), run("b", []), stubVisual);
  assert.equal(report.pageDiffs[0].status, "missing");
});

test("added when current has a url baseline lacks", async () => {
  const report = await diffSiteRuns(baseSite, run("a", []), run("b", [page("/x", "h1")]), stubVisual);
  assert.equal(report.pageDiffs[0].status, "added");
});
```

**Step 2: 테스트 실패 확인**
```bash
cd "D:\16. 자동화 도구\safeAutoTest" && npx tsx --test tests/unit/site-diff-engine.test.ts 2>&1 | head -5
```

**Step 3: `lib/site-diff-engine.ts` 생성**

```ts
import type {
  PageDiff, PageDiffStatus, Site, SitePageCapture, SiteReport, SiteRunResult,
} from "./site-types.ts";

export type VisualDiffFn = (
  baselineCapture: SitePageCapture,
  currentCapture: SitePageCapture,
  diffImagePath: string
) => Promise<{ diffPixels: number; diffRatio: number; diffImagePath: string }>;

export async function diffSiteRuns(
  site: Site,
  baseline: SiteRunResult,
  current: SiteRunResult,
  visualDiff: VisualDiffFn
): Promise<SiteReport> {
  const byUrlBase = new Map(baseline.pages.map((p) => [p.url, p]));
  const byUrlCurr = new Map(current.pages.map((p) => [p.url, p]));
  const allUrls = new Set<string>([...byUrlBase.keys(), ...byUrlCurr.keys()]);

  const pageDiffs: PageDiff[] = [];

  for (const url of allUrls) {
    const b = byUrlBase.get(url);
    const c = byUrlCurr.get(url);

    if (b && !c) { pageDiffs.push({ url, status: "missing", severity: "critical" }); continue; }
    if (!b && c) { pageDiffs.push({ url, status: "added", severity: "info" }); continue; }
    if (!b || !c) continue;

    const domChanged = site.dom.enabled && b.domHash !== c.domHash;
    let visualChanged = false;
    let visualResult: PageDiff["visualDiff"];

    if (site.visual.enabled && b.screenshotPath && c.screenshotPath) {
      const diff = await visualDiff(b, c, `${current.runId}-${encodeURIComponent(url)}.diff.png`);
      visualResult = diff;
      visualChanged = diff.diffRatio > site.visual.maxDiffRatio;
    }

    const status: PageDiffStatus =
      domChanged && visualChanged ? "both" :
      domChanged ? "domChanged" :
      visualChanged ? "visualChanged" : "identical";

    const severity: PageDiff["severity"] =
      status === "both" ? "critical" :
      status === "identical" ? "info" : "warning";

    pageDiffs.push({ url, status, severity, visualDiff: visualResult });
  }

  const hasError = current.errors.length > 0 || baseline.errors.length > 0;
  const hasDifference = pageDiffs.some((d) => d.status !== "identical");
  const overall: SiteReport["overall"] = hasError ? "error" : hasDifference ? "different" : "identical";

  return {
    siteId: site.id,
    baselineRunId: baseline.runId,
    currentRunId: current.runId,
    comparedAt: new Date().toISOString(),
    overall,
    pageDiffs,
  };
}
```

**Step 4: 테스트 통과 확인**
```bash
cd "D:\16. 자동화 도구\safeAutoTest" && npx tsx --test tests/unit/site-diff-engine.test.ts 2>&1 | grep -E "ok|pass|fail"
```
6/6 PASS여야 합니다.

**Step 5: 커밋**
```bash
cd "D:\16. 자동화 도구\safeAutoTest" && git add lib/site-diff-engine.ts tests/unit/site-diff-engine.test.ts && git commit -m "feat(site): add site-diff-engine with url-keyed outer join"
```

결과를 한 줄로 보고: "PASS 6/6, committed" 또는 실패 내용.

